// Form 1: No second argument — runs after every render
useEffect(() => {
  console.log('ran');
});

// Form 2: Empty array — runs once on mount
useEffect(() => {
  console.log('ran once');
}, []);

// Form 3: Dependency array — runs when deps change
useEffect(() => {
  console.log('userId changed to', userId);
}, [userId]);

// Pseudocode for React's dependency comparison:
function shouldReRunEffect(prevDeps, nextDeps) {
  if (prevDeps === null) return true; // no prev deps = first render
  if (prevDeps.length !== nextDeps.length) return true;
  for (let i = 0; i < prevDeps.length; i++) {
    if (!Object.is(prevDeps[i], nextDeps[i])) return true;
  }
  return false; // all deps same, skip effect
}

// With []: prevDeps = [], nextDeps = []
// Loop body never executes — always returns false → effect skipped

useEffect(() => {
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker
      .register('/sw.js')
      .then(reg => console.log('SW registered:', reg.scope))
      .catch(err => console.error('SW error:', err));
  }
}, []); // Register exactly once when app mounts

useEffect(() => {
  analytics.init({ apiKey: process.env.REACT_APP_ANALYTICS_KEY });
  analytics.page(); // record initial page view
}, []); // Init once; subsequent page views tracked by route changes

function Map({ lat, lng }) {
  const mapRef = useRef(null);
  const instanceRef = useRef(null);

  // Create the map once on mount
  useEffect(() => {
    instanceRef.current = new mapboxgl.Map({
      container: mapRef.current,
      style: 'mapbox://styles/mapbox/streets-v11',
      center: [lng, lat],
      zoom: 12,
    });
    return () => instanceRef.current.remove(); // cleanup
  }, []);

  // Fly to new coordinates when lat/lng props change
  useEffect(() => {
    instanceRef.current?.flyTo({ center: [lng, lat] });
  }, [lat, lng]);

  return <div ref={mapRef} style={{ height: 400 }} />;
}

// Two separate effects: one creates the map, one updates it.
// The creation effect runs once; the update effect runs on coord change.

useEffect(() => {
  function handleOnline() { setOnline(true); }
  function handleOffline() { setOnline(false); }

  window.addEventListener('online', handleOnline);
  window.addEventListener('offline', handleOffline);

  return () => {
    window.removeEventListener('online', handleOnline);
    window.removeEventListener('offline', handleOffline);
  };
}, []); // Attach once; cleanup removes them on unmount

useEffect(() => {
  // Opens a WebSocket once on mount
  const ws = new WebSocket('wss://realtime.example.com/feed');
  ws.onmessage = (e) => dispatch(JSON.parse(e.data));

  return () => ws.close(); // Closes when component unmounts
}, []);

// Without the cleanup:
// - WebSocket remains open after the component unmounts
// - Messages keep arriving and dispatching to a dead component
// - Repeat mounts accumulate multiple open sockets

useEffect(() => {
  console.log('effect');
  return () => console.log('cleanup');
}, []);

// Development (StrictMode) console output:
// effect
// cleanup
// effect

// Production console output:
// effect

// If 'effect' runs twice causes problems (e.g. double registration,
// double analytics event), the cleanup must fully reverse the first run.

function Greeting({ name }) {
  useEffect(() => {
    // name is captured from the first render only
    console.log(`Hello, ${name}`);
  }, []); // ← ESLint warns: 'name' is missing from deps

  return <p>Hi {name}</p>;
}

// <Greeting name='Alice' /> → console: 'Hello, Alice'
// prop changes to name='Bob' → no re-run, still 'Hello, Alice' in closure
// The component re-renders correctly, but the effect never sees 'Bob'

function Logger({ onEvent }) {
  // Keep a ref that always points to the latest onEvent callback
  const onEventRef = useRef(onEvent);
  useEffect(() => { onEventRef.current = onEvent; }); // sync every render

  // Subscribe once; read the latest handler via ref
  useEffect(() => {
    const sub = eventStream.subscribe((e) => {
      onEventRef.current(e); // always calls the latest prop
    });
    return () => sub.unsubscribe();
  }, []); // empty deps — subscribe once
}

// Pattern: 'effect event' — stable subscription, up-to-date handler

// ESLint warning:
// React Hook useEffect has missing dependencies: 'userId'.
// Either include it or remove the dependency array.
useEffect(() => {
  fetchUser(userId); // ← uses userId
}, []); // ← empty array is suspicious

// Fix A: Add userId to deps (re-fetches when userId changes — usually correct)
useEffect(() => {
  fetchUser(userId);
}, [userId]);

// Fix B: If truly mount-only, move the value outside the component
//        or use a ref to read it without declaring it as a dep

// Safe: browser-only API inside useEffect with []
useEffect(() => {
  // Runs on client only — never on the server
  const token = localStorage.getItem('authToken');
  if (token) dispatch({ type: 'RESTORE_SESSION', token });
}, []);

// Without useEffect, accessing localStorage during render would
// throw a ReferenceError on the server (localStorage is not defined).

// Module-level: runs once for the entire app (not React-managed)
let mapInstance = null;
function initMap(container) {
  if (!mapInstance) mapInstance = new Map(container);
}

// useEffect []: runs once per component instance
function MapWidget() {
  const ref = useRef(null);
  useEffect(() => {
    // Each <MapWidget> creates its own independent map
    const map = new Map(ref.current);
    return () => map.destroy();
  }, []);
  return <div ref={ref} />;
}

// Two <MapWidget> components = two independent maps
// Module-level pattern = one shared map (likely wrong for reusable components)

// Custom hook: one-time WebSocket connection
function useRealtimeFeed(url) {
  const [messages, setMessages] = useState([]);

  useEffect(() => {
    const ws = new WebSocket(url);
    ws.onmessage = (e) => {
      setMessages(prev => [...prev, JSON.parse(e.data)]);
    };
    ws.onerror = (e) => console.error('WS error', e);
    return () => ws.close();
  }, []); // url treated as stable; caller must memoize if dynamic

  return messages;
}

// Usage — caller is unaware of effects entirely
function Dashboard() {
  const feed = useRealtimeFeed('wss://api.example.com/events');
  return <ul>{feed.map((m, i) => <li key={i}>{m.text}</li>)}</ul>;
}

import { render, screen, waitFor } from '@testing-library/react';

it('initialises analytics on mount', async () => {
  const init = jest.spyOn(analytics, 'init');

  render(<App />);

  // useEffect fires after the render; waitFor handles async
  await waitFor(() => {
    expect(init).toHaveBeenCalledTimes(1);
  });
});

it('does not re-initialise on re-render', async () => {
  const init = jest.spyOn(analytics, 'init');
  const { rerender } = render(<App theme='light' />);

  await waitFor(() => expect(init).toHaveBeenCalledTimes(1));

  rerender(<App theme='dark' />); // triggers re-render
  expect(init).toHaveBeenCalledTimes(1); // still 1 — not re-called
});
